const systemPrompt = systemPrompts[mode] || systemPrompts.strict;

let context = '';
let tokenCount = 0;
let chunks_used = 0;

for (const r of results) {
  const chunkText = '[出典: ' + r.json.source + ']\n' + r.json.content + '\n\n';
  const chunkTokens = estimateTokens(chunkText);
  if (chunks_used === 0 || tokenCount + chunkTokens <= MAX_CONTEXT_TOKENS) {
    context += chunkText;
    tokenCount += chunkTokens;
    chunks_used++;
  } else {
    break;
  }
}

const estimated_tokens = tokenCount;

const prompt = `${systemPrompt}\n\n【参考資料】\n${context}\n【質問】\n${question}\n\n【出力形式（厳守）】\n回答本文を書いた後、必ず最終行に独立した1行として SOURCES_JSON:["参照したsource.pdf"] を出力せよ。これは絶対に省略するな。例: SOURCES_JSON:["test_large.pdf"]`;
return [{ json: { prompt, chunks_used, chunks_total, estimated_tokens } }];

