const body = $('Webhook').first().json.body;
const promptData = $('プロンプト生成').first().json;
const q = (body.question || '').replace(/'/g, "''").slice(0, 500);
const src = body.source ? "'" + body.source.replace(/'/g, "''") + "'" : 'NULL';
const mode = (body.mode || 'strict').replace(/'/g, "''");
const cu = promptData.chunks_used || 0;
const et = promptData.estimated_tokens || 0;
const sql = `INSERT INTO access_logs (endpoint, question, source_filter, mode, chunks_used, estimated_tokens, response_status) VALUES ('/rag-chat', '${q}', ${src}, '${mode}', ${cu}, ${et}, 'success')`;
return [{ json: { sql } }];

const body = $input.first().json.body || {};
const question = body.question;
const mode = body.mode || 'strict';
const uiSources = body.sources || (body.source ? [body.source] : []);

return [{
  json: {
    ...$input.first().json,
    question: question,
    mode: mode,
    uiSources: uiSources,
    needsSourceDetection: true
  }
}];

const input = $('ファイル名検出').first().json;
const question = (input.question || '').toLowerCase();
const uiSources = input.uiSources || [];
const allSources = $('source一覧取得').all().map(row => row.json.source);

const detectedSources = allSources.filter(source => {
  const nameNoExt = source.replace(/\.[^.]+$/, '').toLowerCase();
  const nameFull = source.toLowerCase();
  return question.includes(nameNoExt) || question.includes(nameFull);
});

let finalSources = [...new Set([...uiSources, ...detectedSources])];
const isAllSelected = finalSources.length === 0 || finalSources.length >= allSources.length;

return [{
  json: {
    ...input,
    finalSources: isAllSelected ? null : finalSources,
    detectedSources: detectedSources,
    allSourceCount: allSources.length
  }
}];

const raw = $('LLM回答').first().json.response || '';
const m = raw.match(/^[ \t]*SOURCES_JSON:[ \t]*(\[[^\n]*\])[ \t]*$/m);
let parsedSources = [];
let cleanAnswer = raw;
if (m) {
  try {
    const arr = JSON.parse(m[1]);
    if (Array.isArray(arr)) parsedSources = arr.filter(s => typeof s === 'string');
  } catch (e) {}
  cleanAnswer = raw.replace(m[0], '').replace(/\n{3,}/g, '\n\n').trim();
}
return [{ json: { ...$input.first().json, cleanAnswer, parsedSources } }];

const finalSources = $('source照合').first().json.finalSources || [];
return [{ json: {
  answer: finalSources.length > 0
    ? `指定された資料（${finalSources.join(', ')}）には該当する記載が見つかりませんでした。`
    : 'この資料には該当する記載が見つかりませんでした。',
  sources: [],
  meta: { chunks_used: 0, chunks_total: 0, estimated_tokens: 0 },
  requested_sources: finalSources
}}];
